def match_parens(lst):
    def check_balance(s):
        balance = 0
        for char in s:
            if char == '(':
                balance += 1
            else:
                balance -= 1
            if balance < 0:
                return False
        return balance == 0

    # Check the concatenated combinations
    str1, str2 = lst[0], lst[1]

    # Check both combinations: str1 + str2 and str2 + str1
    if check_balance(str1 + str2) or check_balance(str2 + str1):
        return 'Yes'

    return 'No'

# Examples:
# print(match_parens(['()(', ')']))  # 'Yes'
# print(match_parens([')', ')']))      # 'No'
```
